class Solution {
public:
    vector<int> findAllPeople(int n, vector<vector<int>>& meetings, int firstPerson) {
        vector<int> adj[n];
        for (auto& meeting : meetings) {
            adj[meeting[0]].push_back(meeting[1]);
            adj[meeting[1]].push_back(meeting[0]);
        }
        vector<bool> visited(n, false);
        queue<int> q;
        q.push(firstPerson);
        visited[firstPerson] = true;
        while (!q.empty()) {
            int curr = q.front();
            q.pop();
            for (int neighbor : adj[curr]) {
                if (!visited[neighbor]) {
                    visited[neighbor] = true;
                    q.push(neighbor);
                }
            }
        }
        vector<int> result;
        for (int i = 0; i < n; ++i) {
            if (visited[i]) {
                result.push_back(i);
            }
        }
        return result;
    }
};
